using namespace std;
typedef long long ll;
// typedef __int128 lll;

void solve() {
    int N;
    cin >> N;
    vector<array<int, 2>> points(2 * N);
    for (auto& [x, y] : points) cin >> x >> y;

    int NN = 2 * N;
    vector<vector<int>> dis(NN, vector<int>(NN));
    for (int i = 0; i < NN; ++i) {
        for (int j = i + 1; j < NN; ++j) {
            dis[i][j] = dis[j][i] = abs(points[i][0] - points[j][0]) + abs(points[i][1] - points[j][1]);
        }
    }

    vector<vector<int>> dp(1 << NN, vector<int>(NN, 1e8));
    for (int mask = 1; mask < (1 << NN); ++mask) {
        int cnt = __builtin_popcount(mask);
        if (cnt == 1) {
            int i = __builtin_ctz(mask);
            if (i % 2) dp[mask][i] = abs(points[i][0]) + abs(points[i][1]);
            continue;
        }

        int chefs = 0;
        for (int i = 0; i < NN; i += 2) {
            if (mask & 1 << i) chefs++;
        }
        int tools = cnt - chefs;

        if (tools - chefs > 2) continue;
        if (tools - chefs < 2) {
            for (int i = 0; i < NN; i += 2) {
                if ((mask & 1 << i) == 0 || (mask & 1 << i + 1) == 0) continue;
                int msk = mask ^ 1 << i;
                for (int j = 0; j < NN; ++j) {
                    if ((msk & 1 << j) == 0) continue;
                    dp[mask][i] = min(dp[mask][i], dp[msk][j] + dis[i][j]);
                }
            }
        }
        for (int i = 1; i < NN; i += 2) {
            if ((mask & 1 << i) == 0 || (mask & 1 << i - 1)) continue;
            int msk = mask ^ 1 << i;
            for (int j = 0; j < NN; ++j) {
                if ((msk & 1 << j) == 0) continue;
                dp[mask][i] = min(dp[mask][i], dp[msk][j] + dis[i][j]);
            }
        }
    }
    int ans = 1e8;
    for (int i = 0; i < NN; i += 2) ans = min(ans, dp[(1 << NN) - 1][i] + abs(points[i][0]) + abs(points[i][1]));
    cout << ans << "\n";
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(0);

    int tt = 1;
    cin >> tt;

    while (tt--)
        solve();
}

