import sys 

sys.setrecursionlimit(200000)

class chefAndToolsSolver:
    def __init__(self, n, locations):
        self.n = n 
        self.points = locations 
        self.memo = {} 

    def manhattan_distance(self, p1, p2):
        return abs(p1[0] - p2[0]) + abs(p1[1] - p2[1])

    def solve_recursive(self, current_pos_idx, picked_mask, delivered_mask):
        state = (current_pos_idx, picked_mask, delivered_mask)
        if state in self.memo:
            return self.memo[state]

        if delivered_mask == (1 << self.n) - 1:
            return self.manhattan_distance(self.points[current_pos_idx], self.points[0])

        min_dist = float('inf')
        carried_mask = picked_mask ^ delivered_mask
        num_carried = bin(carried_mask).count('1')

        if num_carried < 2:
            for i in range(self.n):
                if not ((picked_mask >> i) & 1):
                    tool_idx = i + 1 
                    dist_to_tool = self.manhattan_distance(self.points[current_pos_idx], self.points[tool_idx])
                    new_picked_mask = picked_mask | (1 << i)
                    remaining_dist = self.solve_recursive(tool_idx, new_picked_mask, delivered_mask)
                    min_dist = min(min_dist, dist_to_tool + remaining_dist)

        for i in range(self.n):
            if (carried_mask >> i) & 1:
                cook_idx = i + 1 + self.n 
                dist_to_cook = self.manhattan_distance(self.points[current_pos_idx], self.points[cook_idx])
                new_delivered_mask = delivered_mask | (1 << i)
                remaining_dist = self.solve_recursive(cook_idx, picked_mask, new_delivered_mask)
                min_dist = min(min_dist, dist_to_cook + remaining_dist)

        self.memo[state] = min_dist
        return min_dist

    def run(self):
        return self.solve_recursive(0, 0, 0)

def main():
    try:
        num_test_cases_str = sys.stdin.readline()
        if not num_test_cases_str:
            return
        num_test_cases = int(num_test_cases_str)

        for _ in range(num_test_cases):
            n_str = sys.stdin.readline()
            if not n_str:
                continue
            n = int(n_str)

            points = [(0, 0)]
            tools = []
            cooks = []

            for i in range(n):
                line = sys.stdin.readline()
                if not line: continue
                cx, cy, tx, ty = map(int, line.split())
                tools.append((tx, ty))
                cooks.append((cx, cy))

            points.extend(tools)
            points.extend(cooks)

            solver = chefAndToolsSolver(n, points)
            result = solver.run()
            print(result)
    except (IOError, ValueError):
        pass 

if __name__ == "__main__":
    main()

