#include <stdio.h>
#include <stdlib.h>

#define MAXN 15
#define INF 1000000000

int dist(int a[], int b[]) {
    return abs(a[0] - b[0]) + abs(a[1] - b[1]);
}

int min(int a, int b) {
    return a < b ? a : b;
}

int best(int a[], int b[], int c[], int d[]) {
    return min(dist(a, b) + dist(b, c) + dist(c, d),
               dist(a, c) + dist(c, b) + dist(b, d));
}

void solve() {
    int n;
    scanf("%d", &n);
    int c[MAXN + 1][2], t[MAXN + 1][2];
    for (int i = 1; i < n + 1; i++) {
        scanf("%d %d %d %d", &c[i][0], &c[i][1], &t[i][0], &t[i][1]);
    }

    int dp[(1 << (MAXN + 1))][MAXN + 1][MAXN + 1];
    for (int mask = 0; mask < (1 << (n + 1)); mask++) {
        for (int i = 0; i < n + 1; i++) {
            for (int j = 0; j < n + 1; j++) {
                dp[mask][i][j] = INF;
            }
        }
    }

    for (int i = 0; i < n + 1; i++) {
        dp[0][i][0] = 2 * dist(c[0], t[i]);
    }

    for (int i = 1; i < n + 1; i++) {
        for (int key1 = 0; key1 < n + 1; key1++) {
            for (int key2 = 0; key2 < n + 1; key2++) {
                int a[2], b[2];
                if (key2 == 0) {
                    a[0] = c[i][0]; a[1] = c[i][1];
                } else {
                    a[0] = t[key2][0]; a[1] = t[key2][1];
                }
                if (key1 == i) {
                    b[0] = a[0]; b[1] = a[1];
                } else {
                    b[0] = t[i][0]; b[1] = t[i][1];
                }
                dp[1 << i][key2][i] = min(dp[1 << i][key2][i], dp[0][key1][0] + best(c[0], a, b, c[i]));
            }
        }
    }

    for (int mask1 = 0; mask1 < (1 << (n + 1)); mask1++) {
        for (int i = 1; i < n + 1; i++) {
            if (!(mask1 & (1 << i))) continue;
            for (int j = 1; j < n + 1; j++) {
                if (j == i || !(mask1 & (1 << j))) continue;
                for (int key1 = 0; key1 < n + 1; key1++) {
                    if (key1 == 0 || key1 == i) {
                        for (int key2 = 0; key2 < n + 1; key2++) {
                            int a[2], b[2];
                            if (key2 == 0) {
                                a[0] = c[j][0]; a[1] = c[j][1];
                            } else {
                                a[0] = t[key2][0]; a[1] = t[key2][1];
                            }
                            if (key1 == i) {
                                b[0] = a[0]; b[1] = a[1];
                            } else {
                                b[0] = t[i][0]; b[1] = t[i][1];
                            }
                            dp[mask1][key2][i] = min(dp[mask1][key2][i], dp[mask1 ^ (1 << i)][key1][j] + best(c[j], a, b, c[i]));
                        }
                    } else {
                        dp[mask1][key1][i] = min(dp[mask1][key1][i], dp[mask1 ^ (1 << i)][key1][j] + dist(c[j], t[i]) + dist(t[i], c[i]));
                    }
                }
            }
        }
    }

    int ans = INF;
    for (int i = 1; i < n + 1; i++) {
        ans = min(ans, dp[(1 << (n + 1)) - 2][0][i] + dist(c[i], c[0]));
    }
    printf("%d\n", ans);
}

int main() {
    int T = 1;
    scanf("%d", &T);
    while (T--) solve();
    return 0;
}

