import java.io.*;
import java.util.*;

public class Main {

    static final int INF = (int)1e8;

    public static void solve(FastScanner fs) throws Exception {
        int N = fs.nextInt();
        int NN = 2 * N;

        int[][] points = new int[NN][2];
        for (int i = 0; i < NN; i++) {
            points[i][0] = fs.nextInt();
            points[i][1] = fs.nextInt();
        }

        int[][] dis = new int[NN][NN];
        for (int i = 0; i < NN; i++) {
            for (int j = i + 1; j < NN; j++) {
                dis[i][j] = dis[j][i] =
                        Math.abs(points[i][0] - points[j][0]) +
                        Math.abs(points[i][1] - points[j][1]);
            }
        }

        int size = 1 << NN;
        int[][] dp = new int[size][NN];
        for (int i = 0; i < size; i++) Arrays.fill(dp[i], INF);

        for (int mask = 1; mask < size; mask++) {
            int cnt = Integer.bitCount(mask);

            if (cnt == 1) {
                int i = Integer.numberOfTrailingZeros(mask);
                if (i % 2 == 1) {
                    dp[mask][i] = Math.abs(points[i][0]) + Math.abs(points[i][1]);
                }
                continue;
            }

            int chefs = 0;
            for (int i = 0; i < NN; i += 2) {
                if ((mask & (1 << i)) != 0) chefs++;
            }

            int tools = cnt - chefs;

            if (tools - chefs > 2) continue;

            if (tools - chefs < 2) {
                for (int i = 0; i < NN; i += 2) {
                    if ((mask & (1 << i)) == 0 || (mask & (1 << (i + 1))) == 0) continue;

                    int msk = mask ^ (1 << i);

                    for (int j = 0; j < NN; j++) {
                        if ((msk & (1 << j)) == 0) continue;

                        dp[mask][i] = Math.min(dp[mask][i],
                                dp[msk][j] + dis[i][j]);
                    }
                }
            }

            for (int i = 1; i < NN; i += 2) {
                if ((mask & (1 << i)) == 0 || (mask & (1 << (i - 1))) != 0) continue;

                int msk = mask ^ (1 << i);

                for (int j = 0; j < NN; j++) {
                    if ((msk & (1 << j)) == 0) continue;

                    dp[mask][i] = Math.min(dp[mask][i],
                            dp[msk][j] + dis[i][j]);
                }
            }
        }

        int ans = INF;
        int fullMask = (1 << NN) - 1;

        for (int i = 0; i < NN; i += 2) {
            ans = Math.min(ans,
                    dp[fullMask][i] +
                    Math.abs(points[i][0]) +
                    Math.abs(points[i][1]));
        }

        System.out.println(ans);
    }

    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);

        int t = fs.nextInt();
        while (t-- > 0) {
            solve(fs);
        }
    }

    /* Fast Scanner */
    static class FastScanner {
        BufferedReader br;
        StringTokenizer st;

        FastScanner(InputStream is) {
            br = new BufferedReader(new InputStreamReader(is));
        }

        String next() throws IOException {
            while (st == null || !st.hasMoreElements()) {
                st = new StringTokenizer(br.readLine());
            }
            return st.nextToken();
        }

        int nextInt() throws IOException {
            return Integer.parseInt(next());
        }
    }
}
